  `sex` enum('male','female') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `nom` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `code` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `etat` enum('vivant','vendu','mort','archivé') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'vivant',
  `poids_naissance` decimal(6,2) DEFAULT NULL COMMENT 'Poids individuel à la naissance en grammes',
  `etat_sante` enum('Excellent','Bon','Moyen','Faible') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Bon',
  `observations` text COLLATE utf8mb4_unicode_ci,
  `alimentation_jour` decimal(6,2) NOT NULL DEFAULT '0.00',
  `alimentation_semaine` decimal(6,2) NOT NULL DEFAULT '0.00',
