  CONSTRAINT `lapereaux_mise_bas_id_foreign` FOREIGN KEY (`mise_bas_id`) REFERENCES `mises_bas` (`id`) ON DELETE CASCADE,
  CONSTRAINT `lapereaux_naissance_id_foreign` FOREIGN KEY (`naissance_id`) REFERENCES `naissances` (`id`) ON DELETE CASCADE,
  CONSTRAINT `lapereaux_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
