--
-- Table structure for table `naissances`
--

DROP TABLE IF EXISTS `naissances`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `naissances` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `saillie_id` bigint unsigned DEFAULT NULL,
  `mise_bas_id` bigint unsigned NOT NULL,
  `nb_sevre` int NOT NULL DEFAULT '0',
  `poids_moyen_naissance` decimal(5,2) DEFAULT NULL,
  `poids_total_portee` decimal(5,2) DEFAULT NULL,
  `etat_sante` enum('Excellent','Bon','Moyen','Faible') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Bon',
  `observations` text COLLATE utf8mb4_unicode_ci,
  `date_sevrage_prevue` date DEFAULT NULL,
  `date_vaccination_prevue` date DEFAULT NULL,
  `user_id` bigint unsigned NOT NULL,
  `firm_id` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `sex_verified` tinyint(1) NOT NULL DEFAULT '0',
  `sex_verified_at` timestamp NULL DEFAULT NULL,
  `first_reminder_sent_at` timestamp NULL DEFAULT NULL,
  `last_reminder_sent_at` timestamp NULL DEFAULT NULL,
  `reminder_count` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `naissances_saillie_id_foreign` (`saillie_id`),
  KEY `naissances_user_id_foreign` (`user_id`),
  KEY `naissances_etat_sante_index` (`etat_sante`),
  KEY `naissances_mise_bas_id_foreign` (`mise_bas_id`),
  KEY `naissances_firm_id_index` (`firm_id`),
  CONSTRAINT `naissances_firm_id_foreign` FOREIGN KEY (`firm_id`) REFERENCES `firms` (`id`) ON DELETE CASCADE,
  CONSTRAINT `naissances_mise_bas_id_foreign` FOREIGN KEY (`mise_bas_id`) REFERENCES `mises_bas` (`id`) ON DELETE CASCADE,
  CONSTRAINT `naissances_saillie_id_foreign` FOREIGN KEY (`saillie_id`) REFERENCES `saillies` (`id`) ON DELETE SET NULL,
  CONSTRAINT `naissances_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=989 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

